import{_ as t}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as c,c as r,a as e,b as a,d as i,e as s,r as n}from"./app.19408c1e.js";const d={},p=e("h2",{id:"简介",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),a(" 简介")],-1),l=e("p",null,[a("《JavaScript 高级程序设计》 是业界公认的 "),e("code",null,"JavaScript"),a(" 红宝书，书中简单介绍了 "),e("code",null,"JavaScript"),a(" 的历史，并由此展开，全面详实的介绍了 "),e("code",null,"JavaScript"),a(" 的相关知识。")],-1),h={href:"https://humanwhocodes.com/",target:"_blank",rel:"noopener noreferrer"},f=e("sup",{class:"footnote-ref"},[e("a",{href:"#footnote1"},"[1]"),e("a",{class:"footnote-anchor",id:"footnote-ref1"})],-1),S=e("sup",{class:"footnote-ref"},[e("a",{href:"#footnote2"},"[2]"),e("a",{class:"footnote-anchor",id:"footnote-ref2"})],-1),_=s('<p>这本书适合刚入门的前端人员阅读，也适合很多虽然工作很久但从未深入了解过这门语言的前端开发者。</p><h2 id="推荐原因" tabindex="-1"><a class="header-anchor" href="#推荐原因" aria-hidden="true">#</a> 推荐原因</h2><p>《JavaScript 高级程序设计》 是我刚入门前端时读的第一本前端书籍，因本人入门前端较晚，所以看的是第 4 版，在那个时侯，我只是简单的对 <code>HTML</code>、<code>CSS</code>、<code>JavaScript</code> 这三个网页组成部分有所了解，而这本书让我较为全面深入的了解了 <code>JavaScript</code> 这门语言。</p><p>不同于工具书籍，这本书并不仅仅是介绍 <code>JavaScript</code> 一些 Api 的作用，而是从历史出发，带我们了解这些 Api 的出现原因、作用以及解决了什么问题，比如 <code>let/const</code>、<code>class</code>、<code>Promise</code> 等等，让我收获颇丰，不愧 ‘红宝书’ 之名。</p><p>文章会对 《JavaScript 高级程序设计》 的全部章节进行简要总结，对于部分内容可能会另写单独的文章进行较为深入的讲解，这些文章会同步更新附录在对应章节下，对于其他书籍类的文章都会采用这种模式。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>持续更新中</p></div><h2 id="章节" tabindex="-1"><a class="header-anchor" href="#章节" aria-hidden="true">#</a> 章节</h2><h3 id="第-1-章-什么是-javascript" tabindex="-1"><a class="header-anchor" href="#第-1-章-什么是-javascript" aria-hidden="true">#</a> 第 1 章 什么是 JavaScript</h3><p>通过本章知道了 JavaScript 的由来与发展，JavaScript 是 Brendan Eich 于 1995 年开发的一门脚本语言，一开始主要用于表单校验。</p><p>由于浏览器厂商相互竞争，出现了多个版本的 JavaScript，它们的实现不尽相同，为了统一 JavaScript 的语法与特性，规范被制定出来，被称为 ECMAScript。</p><p>JavaScript 并不完全等于 ECMAScript，JavaScript 包含三个部分</p><ul><li>ECMAScript</li><li>BOM</li><li>DOM</li></ul><h4 id="ecmascript" tabindex="-1"><a class="header-anchor" href="#ecmascript" aria-hidden="true">#</a> ECMAScript</h4><p>ECMAScript 只规定了不特定于平台的部分，像 <code>document</code>、<code>location</code> 这些 Api 就是特定于 Web 平台的，不特定于平台意味着只要引擎实现满足 ECMAScript 规范定义，那么只包含这部分的代码能够运行在任何平台下。</p><p>ECMAScript 版本之前以发布次数作为版本号，最近几年由于前端蓬勃发展，ECMAScript 每年都会发布一个新版本，所以目前以年份作为版本号，当然，普遍会将 ES2015 以后的版本统称为 ES6 或 ES6+。</p><h4 id="bom" tabindex="-1"><a class="header-anchor" href="#bom" aria-hidden="true">#</a> BOM</h4><p>BOM，浏览器对象模型，顾名思义，这部分特定于浏览器，提供的 Api 主要用于操作浏览器窗口。</p><h4 id="dom" tabindex="-1"><a class="header-anchor" href="#dom" aria-hidden="true">#</a> DOM</h4><p>DOM，文档对象模型，提供了操作网页文档的 Api，通过 DOM 能够实现页面的动态改变而无需请求一份新的网页文件。</p><p>待续...</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p>Nicholas C. Zakas：独立软件开发者，曾在 Yahoo 和 Box 任职，创建了 <code>ESLint</code> 开源项目，同时也是 《JavaScript 高级程序设计》 1~3 版的作者 <a href="#footnote-ref1" class="footnote-backref">↩︎</a></p></li><li id="footnote2" class="footnote-item"><p>Matt Frisbie：知名前端技术专家，曾在 Google 任职，目前担任 Gosellout 公司 CTO <a href="#footnote-ref2" class="footnote-backref">↩︎</a></p></li></ol></section>',22);function v(u,m){const o=n("ExternalLinkIcon");return c(),r("div",null,[p,l,e("p",null,[a("《JavaScript 高级程序设计》 目前已更至第 4 版，于 2019 年出版发售，前三版的作者是 "),e("a",h,[a("Nicholas C. Zakas"),i(o)]),a(),f,a("，因病不能参与第 4 版的编写，第 4 版作者是 Matt Frisbie"),S,a("。")]),_])}const b=t(d,[["render",v],["__file","JavaScript 高级程序设计.html.vue"]]);export{b as default};
